        String quotedDir = shellSingleQuote(searchDir);
        String quotedPattern = shellSingleQuote(filePattern);

        // 使用 pipefail 确保 find 出错时能正确反映到退出码；限制最多返回10个
        String cmd = String.format("set -o pipefail; find %s -type f -name %s -print | head -n %d",
                quotedDir, quotedPattern, MAX_RESULTS);

        ProcessBuilder pb = new ProcessBuilder("bash", "-c", cmd);
        // 合并标准错误到标准输出，便于统一读取
