                try { readerThread.join(2000); } catch (InterruptedException ie) { Thread.currentThread().interrupt(); }
                return "错误：命令执行超时。";
            }

            // 进程已结束，等待读取线程读完剩余数据
            try { readerThread.join(); } catch (InterruptedException ie) { Thread.currentThread().interrupt(); }

            int exitCode = process.exitValue();
            String result = output.toString().trim();

            if (exitCode != 0) {
                if (result.isEmpty()) {
                    result = "未知错误";
                }
                return "错误：文件查找失败。\n" + result;
            }

            if (result.isEmpty()) {
                return "未找到匹配的文件。";
            }

            return result;
        } catch (IOException e) {
            return "错误：执行命令时发生异常：" + e.getMessage();
        } catch (InterruptedException e) {
            // 恢复中断状态
            Thread.currentThread().interrupt();
            if (process != null) {
                process.destroyForcibly();
            }
            return "错误：命令执行被中断。";
